import{_ as a,c as t,o as n,ai as o}from"./chunks/framework.CObI3_Hx.js";const u=JSON.parse('{"title":"Alasca Tech Talks","description":"","frontmatter":{"title":"Alasca Tech Talks","date":"2026-04-24","banner":"assets/events/20260424_alasca_talks_banner.svg","bannerMobile":"assets/events/20260424_alasca_talks_banner_mobile.svg","bannerSmall":"assets/events/20260424_alasca_talks_banner_small.svg","backgroundhex":"#889aa4ff","tags":["neonephos","alasca"],"rssPubDate":"2026-04-09","published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"EventEntryThemeComponent"},"headers":[],"relativePath":"events/20260424_alasca_tech_talks.md","filePath":"events/20260424_alasca_tech_talks.md"}'),s={name:"events/20260424_alasca_tech_talks.md"};function r(l,e,i,c,d,p){return n(),t("div",null,e[0]||(e[0]=[o('<p>At the <a href="https://alasca.cloud/en/alasca-tech-talks/" target="_blank" rel="noreferrer">upcoming Alasca Tech Talks</a> NeoNephos has been given the opportunity to present!</p><p><strong>Title</strong>: ALASCA Tech-Talk #35: Sovereignty = func(Ecosystems, Interoperability);</p><blockquote><p>The warnings of the Draghi Report serve as a strategic wake-up call. To date, many European initiatives aimed at building a sovereign alternative have failed due to their own structures, national preferences, and, ultimately, the fragmentation of technical offerings. The strategic alternative lies in foundation-led, vendor-neutral open-source software and interoperable &amp; portable standards. Through 8RA and the funding projects of the &quot;Important Project of Common European Interest&quot; (IPCEI), work is underway to create a federated multi-provider cloud-edge continuum. A few companies from the IPCEI-CIS have recognized this wake-up call and transitioned their projects and operations into the neutral NeoNephos Foundation. This presentation will address the challenges posed within the IPCEI, outline some of the technical considerations of NeoNephos, and delve into a project featuring a new, innovative approach. Ultimately, the responsibility lies with us: developers, project managers, and decision-makers. We already rely heavily on open source (from Linux and Kubernetes to OTEL, ... PyTorch, vLLM, upto llm-d, if you are also into AI). The question is: can we succeed in creating a federated yet technically homogeneous market offering and start competing on top of a digital commons, not within?</p></blockquote><p><a href="https://alasca.cloud/wp-content/uploads/2026/04/alasca-tech-talk-35.ics" target="_blank" rel="noreferrer">Save the date</a> and <strong><a href="https://bbb.cloudandheat.com/rooms/a6x-ubv-eje-uuv/join" target="_blank" rel="noreferrer">dial in directly</a></strong>!</p>',4)]))}const _=a(s,[["render",r]]);export{u as __pageData,_ as default};
